  updateSeedScreen: (clipId, screenId, data) => request(`/clips/${clipId}/seed-screen/${screenId}`, { method: 'PATCH', body: data }),
  deleteSeedScreen: (clipId, screenId) => request(`/clips/${clipId}/seed-screen/${screenId}`, { method: 'DELETE' }),
